operations.body:
query SearchProducts($query: String!) {
  search(query: $query) {
    id
    ...ProductTile_product
    __typename
  }
}

fragment ProductTile_product on Product {
  id
  thumbnail
  title
  rating
  price
  __typename
}

query GetProduct($id: ID!) {
  product(id: $id) {
    id
    title
    rating
    price
    description
    images
    __typename
  }
}

mutation AddToCart($productId: ID!, $quantity: Int!) {
  addToCart(productId: $productId, quantity: $quantity) {
    id
    __typename
  }
}

query TopProducts {
  topProducts {
    id
    ...ProductTile_product
    __typename
  }
  categories {
    slug
    ...CategoryTile_category
    __typename
  }
}

fragment CategoryTile_category on CategoryInfo {
  image
  name
  slug
  __typename
}

fragment ProductTile_product on Product {
  id
  thumbnail
  title
  rating
  price
  __typename
}

query BrowseProducts($category: Category!, $sortBy: String, $order: Order, $limit: Int, $skip: Int) {
  products(
    category: $category
    sortBy: $sortBy
    order: $order
    limit: $limit
    skip: $skip
  ) {
    limit
    skip
    total
    results {
      id
      ...ProductTile_product
      __typename
    }
    __typename
  }
  categories {
    name
    slug
    __typename
  }
}

fragment ProductTile_product on Product {
  id
  thumbnail
  title
  rating
  price
  __typename
}

mutation UpdateCartItemQuantity($cartItemId: ID!, $quantity: Int!) {
  updateCartItemQuantity(id: $cartItemId, quantity: $quantity) {
    id
    quantity
    __typename
  }
}

query ViewCart {
  cart {
    id
    quantity
    product {
      id
      price
      thumbnail
      title
      __typename
    }
    __typename
  }
}
